import json

with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

# Build lookup: project_name -> framework -> package -> version
def build_lookup(data):
    lookup = {}
    for proj in data['projects']:
        name = proj['path'].split('/')[-1]
        lookup[name] = {}
        for fw in proj['frameworks']:
            lookup[name][fw['framework']] = {}
            for pkg in fw['topLevelPackages']:
                lookup[name][fw['framework']][pkg['id']] = pkg['resolvedVersion']
    return lookup

b = build_lookup(baseline)
a = build_lookup(after)

print('=== CHANGES ===')
changes = False
for proj in sorted(set(list(b.keys()) + list(a.keys()))):
    for fw in sorted(set(list(b.get(proj,{}).keys()) + list(a.get(proj,{}).keys()))):
        bp = b.get(proj,{}).get(fw,{})
        ap = a.get(proj,{}).get(fw,{})
        for pkg in sorted(set(list(bp.keys()) + list(ap.keys()))):
            bv = bp.get(pkg)
            av = ap.get(pkg)
            if bv != av:
                changes = True
                print(f'{proj} ({fw}) | {pkg} | {bv} -> {av}')

if not changes:
    print('No changes detected')

print()
print('=== UNCHANGED ===')
for proj in sorted(b.keys()):
    for fw in sorted(b[proj].keys()):
        for pkg in sorted(b[proj][fw].keys()):
            bv = b[proj][fw][pkg]
            av = a.get(proj,{}).get(fw,{}).get(pkg)
            if bv == av:
                print(f'{proj} ({fw}) | {pkg} | {bv}')
